INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'edceb887-f8c9-42e6-abee-9d4b9e4abc48',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis + BullMQ — Job Priorities, Rate Limiting, Repeatable Jobs, and Dependencies$escape$,
  $escape$BullMQ stores every job as a Redis hash and uses sorted sets (ZSET) to implement its queue mechanics — making Redis data structures first-class citizens, not an implementation detail.

Job priorities use a ZSET keyed `bull:{queue}:wait`, where the score is the priority value. Lower score = processed first. Assign `priority: 1` for critical jobs; default is 0 (FIFO within the same priority).

Rate limiting is enforced via a Redis token-bucket pattern. Set `{ limiter: { max: 100, duration: 60000 } }` on the worker — BullMQ writes a rolling window key in Redis and blocks processing when the bucket is exhausted, without dropping jobs.

Repeatable jobs persist their cron definition in `bull:{queue}:repeat` (another ZSET scored by next-run timestamp). BullMQ's scheduler polls this set and re-enqueues automatically — survives worker restarts because state lives in Redis.

Job dependencies use `FlowProducer`, which atomically inserts a parent job into `bull:{queue}:waiting-children` via a Lua script. The parent only moves to the active set once all child job IDs are removed from that key — coordinated entirely through Redis key operations.$escape$,
  $escape$import { Queue, Worker, FlowProducer } from 'bullmq';
import { Redis } from 'ioredis';

const connection = new Redis({ maxRetriesPerRequest: null });
const queue = new Queue('tasks', { connection });

// Priority job — processed before priority:5 jobs
await queue.add('critical-alert', { userId: 42 }, { priority: 1 });

// Repeatable job — cron stored in bull:tasks:repeat ZSET
await queue.add('daily-digest', {}, { repeat: { cron: '0 9 * * *' } });

// Rate-limited worker — token bucket enforced in Redis
const worker = new Worker('tasks', async job => { await process(job); }, {
  connection,
  limiter: { max: 50, duration: 10_000 },
});

// Dependency flow — parent waits in bull:tasks:waiting-children
const flow = new FlowProducer({ connection });
await flow.add({
  name: 'send-report',
  queueName: 'tasks',
  children: [
    { name: 'fetch-data', queueName: 'tasks', data: { source: 'db' } },
    { name: 'render-pdf', queueName: 'tasks', data: { template: 'v2' } },
  ],
});$escape$,
