INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fd54cba5-6632-4328-80fd-66cf6a35d716',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis-Backed Celery — Task Routing, Beat Scheduling, and Result Chains$escape$,
  $escape$When Redis is both your Celery broker and result backend, tasks land in Redis lists (one per queue) and results are stored as Redis keys with a configurable TTL. Route tasks to named queues by setting `task_routes` — Celery pushes to `celery:default`, `celery:priority`, etc. as plain Redis list keys via LPUSH/BRPOP. The beat scheduler persists its state in `celerybeat-schedule` (a shelve file) by default, but with `django-celery-beat` it stores schedules in your DB — Redis just carries the dispatched tasks. For result backends, set `result_expires` to control how long Redis holds task state keys (default 24 h); use `AsyncResult(task_id).get()` to block on completion or `.state` to poll. Chain tasks with `.si()` (immutable signature) to prevent upstream results bleeding into downstream args — critical when Redis result keys hold large payloads you don't want auto-forwarded. Use `chord` for fan-out/fan-in: N parallel tasks finish, Redis accumulates results, callback fires once all keys are resolved.$escape$,
  $escape$from celery import Celery, chain, chord

app = Celery('worker',
    broker='redis://localhost:6379/0',
    backend='redis://localhost:6379/1')

app.conf.update(
    task_routes={
        'tasks.send_email': {'queue': 'priority'},
        'tasks.generate_report': {'queue': 'default'},
    },
    result_expires=3600,  # Redis TTL for result keys
)

@app.task
def fetch(user_id): return user_id

@app.task
def process(user_id): return f'done:{user_id}'

# Chain: fetch result is NOT passed to process (immutable)
pipeline = chain(fetch.si(42), process.si(42))
result = pipeline.apply_async()
print(result.get())  # blocks until Redis result key resolves$escape$,
  $escape$python$escape$,
