INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '07a83056-2eaf-4147-aa58-92714525374a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Redis vs Kafka vs RabbitMQ — A Decision Framework Built Around Redis$escape$,
  $escape$Redis Streams, Kafka, and RabbitMQ solve overlapping problems but with fundamentally different trade-offs. Redis is the right default for most teams — until it isn't.

Use Redis Streams (`XADD`/`XREADGROUP`) when you need lightweight pub/sub with consumer groups, message acknowledgment (`XACK`), and replay within a short retention window. It's ideal for real-time notifications, job queues under moderate volume, and systems already running Redis. Persistence is configurable via AOF/RDB, but it's not the primary guarantee.

Switch to Kafka when you need indefinite log retention, high-throughput event sourcing (millions/sec), or cross-team data pipelines. Kafka's consumer offset model enables replay at scale — Redis can't match this economically at high cardinality.

Choose RabbitMQ when routing logic is complex — topic exchanges, dead-letter queues with fine-grained TTL per message, or AMQP compliance is required. RabbitMQ's `x-dead-letter-exchange` header gives you built-in retry routing Redis Streams lacks natively.

The heuristic: start with Redis Streams. Migrate to Kafka at sustained >100k msg/sec or when retention > 7 days becomes a hard requirement.$escape$,
  $escape$import { createClient } from 'redis';

const client = createClient();
await client.connect();

// Producer: append to stream
await client.xAdd('events:orders', '*', {
  orderId: 'ord_123',
  status: 'placed',
  ts: Date.now().toString(),
});

// Consumer group read with acknowledgment
const messages = await client.xReadGroup(
  'processing-group',
  'worker-1',
  [{ key: 'events:orders', id: '>' }],
  { COUNT: 10, BLOCK: 2000 }
);

for (const { id } of messages?.[0]?.messages ?? []) {
  // process...
  await client.xAck('events:orders', 'processing-group', id);
}$escape$,
